parameters.jsCode:
const raw = $input.first().json.body;
const body = typeof raw === "string" ? JSON.parse(raw) : raw;

const name = body["name"] || body["FULL name"] || "";
const age = body["age"] || "";
const location = body["location"] || "";
const email = body["email"] || body["email address"] || "";
const language = (body["language"] || body["preferred language "] || "english").trim().toLowerCase();
const requestType = (body["requestType"] || body["type of request"] || "general").toLowerCase();
const description = body["description"] || body["describe request"] || "";
const phone = body["phone"] || "";

let urgency = "Low";
const urgencyKeywords = ["urgent", "emergency", "help", "asap", "critical", "अस्पताल", "मदद", "तुरंत"];
urgencyKeywords.forEach(keyword => {
  if (description.toLowerCase().includes(keyword)) {
    urgency = "High";
  }
});

return [{ json: { name, age, email, location, language, phone, requestType, description, urgency } }];

