			"description": "The category of the support request"
		},
		"urgency": {
			"type": "string",
			"enum": ["High", "Medium", "Low"],
			"description": "The urgency level of the request"
		},
		"translatedText": {
			"type": "string",
			"description": "English translation of the original text"
		},
		"originalLanguage": {
			"type": "string",
			"description": "The detected language of the original text"
		}
	},
	"required": ["category", "urgency", "translatedText", "originalLanguage"]
}

